// // This module implements a 16-bit down/up counter. It counts down when the 'up' signal is high and counts up when the 'down' signal is high.
module up_down_counter(
    input               clk         ,   
    input               rst         ,
    input               up          ,
    input               down        ,

    output  reg [15:0]  count
);

   //count logic
   always @(posedge clk or posedge rst) begin
       if(rst) begin
          count <= 0;
       end
       else if(up) begin
          count <= count + 1;
       end
       else if(down) begin
          count <= count - 1;
       end
   end

endmodule
